 23→	scmHeadBoolean   scmHead = 6
 24→	scmHeadProcedure scmHead = 14
 25→	scmHeadStream    scmHead = 17
 26→	scmHeadError     scmHead = 22
 27→	scmHeadNative    scmHead = 23
 28→	scmHeadRaw       scmHead = 42
 29→)
