 87→func MakeNative(fn func(*ControlFlow), require int, captured ...Obj) Obj {
 88→	tmp := scmNative{
 89→		scmHead:  scmHeadNative,
 90→		fn:       fn,
 91→		require:  require,
 92→		captured: captured,
 93→	}
 94→	return &tmp.scmHead
 95→}
