109→// MakeRaw makes a struct into a raw object.
110→// Usage:
111→//
112→//	type T struct {
113→//	   scmHead int
114→//	   ... // xxx
115→//	}
116→//
117→// tmp := &T{}
118→// raw := MakeRaw(&tmp.scmHead)
119→func MakeRaw(scmHead *int) Obj {
120→	*scmHead = int(scmHeadRaw)
121→	return Obj(unsafe.Pointer(scmHead))
122→}
