247→const fixnumCount = 1 << 20
248→
249→var addrForFixnum [fixnumCount]byte
250→
251→var fixnumBaseAddr = unsafe.Pointer(&addrForFixnum[0])
252→var fixnumEndAddr = unsafe.Add(fixnumBaseAddr, fixnumCount)
