254→type trieNode struct {
255→	children [256]*trieNode
256→	value    scmSymbol
257→}
258→
259→var symbolRoot trieNode
260→
261→func trieFindOrInsert(str string) *trieNode {
262→	p := &symbolRoot
263→	for i := 0; i < len(str); i++ {
264→		v := str[i]
265→		if p.children[v] == nil {
266→			p.children[v] = &trieNode{
267→				value: scmSymbol{
268→					scmHead: scmHeadSymbol,
269→					str:     str[:i+1],
270→				},
271→			}
272→		}
273→		p = p.children[v]
274→	}
275→	return p
276→}
