278→func init() {
279→	uptime = time.Now()
280→	tmp1 := &scmBoolean{scmHeadBoolean, false}
281→	False = Obj(&tmp1.scmHead)
282→
283→	tmp2 := &scmBoolean{scmHeadBoolean, true}
284→	True = Obj(&tmp2.scmHead)
285→
286→	tmp3 := &scmPair{scmHeadNull, nil, nil}
