308→func MakeInteger(v int) Obj {
309→	if v >= 0 && v < fixnumCount {
310→		return Obj(unsafe.Pointer(unsafe.Add(fixnumBaseAddr, v)))
311→	}
312→	return makeInteger(v)
313→}
314→
315→func isFixnum(o Obj) bool {
316→	v := uintptr(unsafe.Pointer(o))
317→	if v >= uintptr(fixnumBaseAddr) && v < uintptr(fixnumEndAddr) {
318→		return true
319→	}
320→	return false
321→}
