328→func MakeNumber(f float64) Obj {
329→	if isPreciseInteger(f) {
330→		return MakeInteger(int(f))
331→	}
332→
333→	tmp := scmNumber{scmHeadNumber, f}
334→	return &tmp.scmHead
335→}
