392→func makeProcedure(arg Obj, body Obj, env Obj) Obj {
393→	tmp := scmProcedure{
394→		scmHead: scmHeadProcedure,
395→		body:    body,
396→		env:     env,
397→	}
398→	if *arg == scmHeadSymbol {
399→		tmp.arg = []Obj{arg}
400→		tmp.arity = 1
401→	} else {
402→		tmp.arg = ListToSlice(arg)
403→		tmp.arity = len(tmp.arg)
404→	}
405→	return &tmp.scmHead
406→}
