408→func ObjString(o Obj) string {
409→	return (*scmHead)(o).GoString()
410→}
411→
412→func (o *scmPair) fmt(buf io.Writer, start bool) {
413→	if start {
414→		fmt.Fprintf(buf, "(%s", ObjString(o.car))
415→	} else {
416→		fmt.Fprintf(buf, " %s", ObjString(o.car))
417→	}
418→	switch *o.cdr {
419→	case scmHeadNull:
420→		fmt.Fprintf(buf, ")")
421→	case scmHeadPair:
422→		mustPair(o.cdr).fmt(buf, false)
423→	default:
424→		fmt.Fprintf(buf, " . %s)", ObjString(o.cdr))
425→	}
426→}
427→
428→func (o *scmHead) GoString() string {
429→	switch *o {
430→	case scmHeadNumber:
431→		f := mustNumber(o)
432→		if !isPreciseInteger(f) {
433→			return fmt.Sprintf("%f", f)
434→		}
435→		return fmt.Sprintf("%d", int(f))
436→	case scmHeadPair:
437→		var buf bytes.Buffer
438→		mustPair(o).fmt(&buf, true)
439→		return buf.String()
440→	case scmHeadVector:
441→		return "#vector"
442→	case scmHeadNull:
443→		return "()"
444→	case scmHeadString:
445→		return fmt.Sprintf(`"%s"`, mustString(o))
446→	case scmHeadSymbol:
447→		return GetSymbol(o)
448→	case scmHeadBoolean:
449→		switch o {
450→		case True:
451→			return "true"
452→		case False:
453→			return "false"
454→		default:
455→			return "Boolean(something wrong)"
456→		}
457→
458→	case scmHeadError:
459→		return fmt.Sprintf("Error(%s)", mustError(o).err)
460→	case scmHeadProcedure:
461→		return "#procedure"
462→	case scmHeadStream:
463→		return "#stream"
464→	case scmHeadRaw:
465→		return "#raw"
466→	case scmHeadNative:
467→		prim := MustNative(o)
468→		if len(prim.name) > 0 {
469→			return fmt.Sprintf("#primitive(%s)", prim.name)
470→		}
471→		return "#native"
472→	}
473→	return fmt.Sprintf("unknown type %d", *o)
474→}
