165→func PrimStr(o Obj) Obj {
166→	switch *o {
167→	case scmHeadPair:
168→		// Pair may contain recursive list.
169→		panic(MakeError("can't str pair object"))
170→	case scmHeadNull:
171→		return MakeString("()")
172→	case scmHeadSymbol:
173→		str := GetSymbol(o)
174→		return MakeString(str)
175→	case scmHeadNumber:
176→		if isFixnum(o) {
177→			return MakeString(fmt.Sprintf("%d", mustInteger(o)))
178→		}
179→		f := mustNumber(o)
180→		if !isPreciseInteger(f) {
181→			return MakeString(fmt.Sprintf("%f", f))
182→		}
183→		return MakeString(fmt.Sprintf("%d", int(f)))
184→	case scmHeadString:
185→		return MakeString(fmt.Sprintf(`"%s"`, mustString(o)))
186→	case scmHeadProcedure:
187→		return MakeString("#<procedure >")
188→	case scmHeadBoolean:
189→		switch o {
190→		case True:
191→			return MakeString("true")
192→		case False:
193→			return MakeString("false")
194→		}
195→	case scmHeadError:
196→		err := mustError(o)
197→		return MakeString("#<err " + err.err + ">")
198→	case scmHeadStream:
199→		return MakeString("#<stream >")
200→	case scmHeadRaw:
201→		return MakeString("#<raw >")
202→	case scmHeadNative:
203→		n := MustNative(o)
204→		if len(n.name) > 0 {
205→			return MakeString(fmt.Sprintf("#<primitive %s>", n.name))
206→		} else {
207→			return MakeString(fmt.Sprintf("#<native %v>", *n))
208→		}
209→	default:
210→		return MakeString("PrimStr unknown")
211→
212→	}
213→	return MakeString("wrong input, the object is not atom ...")
214→}
