664→func MakePrimitive(name string, arity int, f interface{}) Obj {
665→	var fn func(*ControlFlow)
666→	switch arity {
667→	case 1:
668→		raw, ok := f.(func(Obj) Obj)
669→		if !ok {
670→			panic(fmt.Sprintf("MakePrimitive %s failed: %#v", name, f))
671→		}
672→		fn = wrapf1(raw)
673→	case 2:
674→		raw, ok := f.(func(x, y Obj) Obj)
675→		if !ok {
676→			panic(fmt.Sprintf("MakePrimitive %s failed: %#v", name, f))
677→		}
678→		fn = wrapf2(raw)
679→	case 3:
680→		raw, ok := f.(func(x, y, z Obj) Obj)
681→		if !ok {
682→			panic(fmt.Sprintf("MakePrimitive %s failed: %#v", name, f))
683→		}
684→		fn = wrapf3(raw)
685→	default:
686→		panic(fmt.Sprintf("MakePrimitive %s failed: %#v", name, f))
687→	}
688→	tmp := &scmNative{
689→		scmHead: scmHeadNative,
690→		name:    name,
691→		require: arity,
692→		fn:      fn,
693→	}
694→	return Obj(&tmp.scmHead)
695→}
