  8→type ControlFlowKind int
  9→
 10→const (
 11→	ControlFlowReturn ControlFlowKind = iota
 12→	ControlFlowEval
 13→	ControlFlowApply
 14→)
 15→
 16→type ControlFlow struct {
 17→	// controlFlowReturn: result = data[0]
 18→	// controlFlowApply: fn, args = data[0], data[1], data[2] ...
 19→	// controlFlowEval: exp, env = data[0], data[1]
 20→	kind ControlFlowKind
 21→
 22→	// data[pos : len(data)] is the arguments to current function.
 23→	// Why it needs to be a stack?
 24→	// Most of the time, an array is sufficient. But when eval expression like
 25→	// (f (g1 h) (g2 n) ...), the stack is used to store the temporary arguments
 26→	data []Obj
 27→	pos  int
 28→}
 29→
 30→func (ctl *ControlFlow) TailEval(exp Obj, env Obj) {
 31→	ctl.data = ctl.data[:ctl.pos]
 32→	ctl.data = append(ctl.data, exp)
 33→	ctl.data = append(ctl.data, env)
 34→	ctl.kind = ControlFlowEval
 35→}
 36→
 37→func (ctl *ControlFlow) TailApply(f Obj, args ...Obj) {
 38→	ctl.data = ctl.data[:ctl.pos]
 39→	ctl.data = append(ctl.data, f)
 40→	// TODO: Change the function signature.
 41→	// Using args ... is not good for performance, there is a copy here.
 42→	ctl.data = append(ctl.data, args...)
 43→	ctl.kind = ControlFlowApply
 44→}
 45→
 46→func (ctl *ControlFlow) Return(result Obj) {
 47→	ctl.data = ctl.data[:ctl.pos]
 48→	ctl.data = append(ctl.data, result)
 49→	ctl.kind = ControlFlowReturn
 50→}
 51→
 52→func (ctl *ControlFlow) Get(n int) Obj {
 53→	return ctl.data[ctl.pos+n]
 54→}
 55→
 56→// trampoline is introduced for tail call optimization.
 57→func trampoline(ctl *ControlFlow) Obj {
 58→	for ctl.kind != ControlFlowReturn {
 59→		switch ctl.kind {
 60→		case ControlFlowEval:
 61→			eval(ctl)
 62→		case ControlFlowApply:
 63→			apply(ctl)
 64→		}
 65→	}
 66→	ret := ctl.data[ctl.pos]
 67→	ctl.data = ctl.data[:ctl.pos]
 68→	return ret
 69→}
 70→
 71→func evalExp(e *ControlFlow, exp Obj, env Obj) Obj {
 72→	e.TailEval(exp, env)
 73→	return trampoline(e)
 74→}
 75→
 76→func evalIf(e *ControlFlow, a, b, c Obj, env Obj) {
 77→	t := evalExp(e, a, env)
 78→	switch t {
 79→	case True:
 80→		e.TailEval(b, env)
 81→		return
 82→	case False:
 83→		e.TailEval(c, env)
 84→		return
 85→	}
 86→	panic("second argument of if should be boolean")
 87→}
