105→// partialApply works when Required > providArgs
106→func partialApply(required int, providArgs []Obj, env Obj, proc Obj) Obj {
107→	// Partial apply...
108→	// (f x y z) => (lambda (z) (f x y z)) with x y in env
109→	symbols := makeTempSymbols(required)
110→	env1 := envExtend(env, symbols[:len(providArgs)], providArgs)
111→
112→	args := Nil
113→	for i, count := len(symbols)-1, required-len(providArgs); count > 0; count-- {
114→		args = cons(symbols[i], args)
115→		i--
116→	}
117→
118→	body := Nil
119→	for i := len(symbols) - 1; i >= 0; i-- {
120→		body = cons(symbols[i], body)
121→	}
122→	body = cons(proc, body)
123→
124→	return makeProcedure(args, body, env1)
125→}
