127→func makeTempSymbols(n int) []Obj {
128→	ret := make([]Obj, n)
129→	for i := 0; i < n; i++ {
130→		ret[i] = MakeSymbol(fmt.Sprintf("tmp%d", i))
131→	}
132→	return ret
133→}
