140→func Eval(e *ControlFlow, exp Obj) (res Obj) {
141→	defer func() {
142→		if r := recover(); r != nil {
143→			var buf [4096]byte
144→			n := runtime.Stack(buf[:], false)
145→			if x, ok := r.(Obj); ok && IsError(x) {
146→				fmt.Println("Panic:", mustError(x))
147→			} else {
148→				fmt.Println("Panic:", r)
149→			}
150→			fmt.Println("Recovered in Eval:", ObjString(exp))
151→			str := string(buf[:n])
152→			// fmt.Println(str)
153→			res = MakeError(str)
154→		}
155→	}()
156→	res = evalExp(e, exp, Nil)
157→	return
