165→func Try(e *ControlFlow, f Obj) (res tryResult) {
166→	defer func() {
167→		if err := recover(); err != nil {
168→			if val, ok := err.(Obj); ok {
169→				if IsError(val) {
170→					res = tryResult{e: e, data: val}
171→					return
172→				}
173→			}
174→			// Unexpected panic?
175→			var buf [4096]byte
176→			n := runtime.Stack(buf[:], false)
177→			fmt.Println("Panic:", err)
178→			fmt.Println("Recovered in Try:", ObjString(f))
179→			fmt.Println(string(buf[:n]))
180→		}
181→	}()
182→	MustNative(f)
183→	val := Call(e, f)
184→	res = tryResult{e: e, data: val}
185→	return
186→}
