195→func apply(ctl *ControlFlow) {
196→	f := ctl.data[ctl.pos]
197→	args := ctl.data[ctl.pos+1:]
198→	switch *f {
199→	case scmHeadProcedure:
200→		args := ctl.data[ctl.pos+1:]
201→		proc := mustProcedure(f)
202→		switch {
203→		case len(args) < proc.arity:
204→			ctl.Return(partialApply(proc.arity, args, proc.env, f))
205→			return
206→		case len(args) == proc.arity:
207→			newEnv := envExtend(proc.env, proc.arg, args)
208→			ctl.TailEval(proc.body, newEnv)
209→			return
210→		case len(args) > proc.arity:
211→			newEnv := envExtend(proc.env, proc.arg, args[:proc.arity])
212→			res := evalExp(ctl, proc.body, newEnv)
213→			ctl.TailApply(res, args[proc.arity:]...)
214→			return
215→		}
216→	case scmHeadNative:
217→		fn := MustNative(f)
218→		provided := len(fn.captured) + len(args)
219→		required := fn.require
220→		if provided != required {
221→			panic("partial apply unsupported")
222→		}
223→		if len(fn.captured) > 0 {
224→			// Captured data should come fisrt, then the arguments.
225→			ctl.data = append(ctl.data, make([]Obj, len(fn.captured))...)
226→			dst := ctl.data[len(ctl.data)-len(args):]
227→			copy(dst, args)
228→			dst = ctl.data[ctl.pos+1 : ctl.pos+1+len(fn.captured)]
229→			copy(dst, fn.captured)
230→		}
231→		fn.fn(ctl)
232→		return
233→	}
234→	panic("can't apply object")
235→}
