237→func envGet(env Obj, sym Obj) (Obj, bool) {
238→	for env != Nil {
239→		pair := car(env)
240→		if car(pair) == sym {
241→			return cdr(pair), true
242→		}
243→		env = cdr(env)
244→	}
245→	return nil, false
246→}
