255→func eval(e *ControlFlow) {
256→	exp := e.data[e.pos]
257→	env := e.data[e.pos+1]
258→
259→	switch *exp {
260→	// handle constant
261→	case scmHeadNumber, scmHeadString, scmHeadVector, scmHeadBoolean, scmHeadNull, scmHeadProcedure /* , scmHeadPrimitive */ :
262→		e.Return(exp)
263→		return
264→	case scmHeadSymbol:
265→		if val, ok := envGet(env, exp); ok {
266→			exp = val
267→		}
268→		e.Return(exp)
269→		return
270→	}
271→
272→	pair := mustPair(exp)
273→	if IsSymbol(pair.car) {
274→		exp = pair.cdr // handle special form
275→		switch pair.car {
276→		case symDefun: // (defun f (x y) z)
277→			proc := makeProcedure(cadr(exp), caddr(exp), env)
278→			funName := car(exp)
279→			BindSymbolFunc(funName, proc)
280→			e.Return(funName)
281→			return
282→		case symLambda: // (lambda x x)
283→			e.Return(makeProcedure(car(exp), cadr(exp), env))
284→			return
285→		case symFreeze: // (freeze body)
286→			e.Return(makeProcedure(Nil, car(exp), env))
287→			return
288→		case symLet: // (let x y z)
289→			args := evalExp(e, cadr(exp), env)
290→			newEnv := envExtend(env, []Obj{car(exp)}, []Obj{args})
291→			e.TailEval(caddr(exp), newEnv)
292→			return
293→		case symAnd:
294→			evalAnd(e, car(exp), cadr(exp), env)
295→			return
296→		case symOr:
297→			evalOr(e, car(exp), cadr(exp), env)
298→			return
299→		case symIf: // (if a b c)
300→			if listLength(pair.cdr) == 3 {
301→				evalIf(e, car(exp), cadr(exp), caddr(exp), env)
302→				return
303→			} // if may also be a function for partial apply
304→		case symCond: // (cond (false 1) (true 2))
305→			evalCond(e, exp, env)
306→			return
307→		case symType:
308→			// (type XXX (list Symbol)) => XXX, just ignore the second one
309→			e.TailEval(car(exp), env)
310→			return
311→		case symTrapError: // (trap-error ~body ~handler)
312→			evalTrapError(e, exp, env)
313→			return
314→		case symDo: // (do A A)
315→			evalExp(e, car(exp), env)
316→			e.TailEval(cadr(exp), env)
317→			return
318→		}
319→	}
320→
321→	savePOS := e.pos
322→	fn := evalFunction(e, pair.car, env)
323→	e.data = e.data[:e.pos]
324→	e.data = append(e.data, fn)
325→	e.pos++
326→
327→	args := pair.cdr
328→	for *args == scmHeadPair {
329→		v := evalExp(e, car(args), env)
330→		if *v == scmHeadError {
331→			e.pos = savePOS
332→			e.TailApply(fn, v)
333→			return
334→		}
335→		e.data = append(e.data, v)
336→		e.pos++
337→		args = cdr(args)
338→	}
339→	e.pos = savePOS
340→	e.kind = ControlFlowApply
341→}
342→
343→func evalCond(e *ControlFlow, l Obj, env Obj) {
344→	for *l == scmHeadPair {
345→		curr := car(l)
346→		if evalExp(e, car(curr), env) == True {
347→			e.TailEval(cadr(curr), env)
348→			return
349→		}
350→		l = cdr(l)
351→	}
352→	e.Return(Nil)
353→}
354→
355→func evalTrapError(e *ControlFlow, exp Obj, env Obj) {
356→	savePOS := e.pos
357→	defer func() {
358→		if err := recover(); err != nil {
359→			if val, ok := err.(Obj); ok {
360→				if IsError(val) {
361→					e.pos = savePOS
362→					e.data = e.data[:e.pos]
363→					handle := evalFunction(e, cadr(exp), env)
364→					e.TailApply(handle, val)
365→					return
366→				}
367→			}
368→			// Unexpected panic?
369→			var buf [4096]byte
370→			n := runtime.Stack(buf[:], false)
371→			fmt.Println("Panic:", err)
372→			fmt.Println("Recovered in trap-error:", ObjString(exp))
373→			fmt.Println(string(buf[:n]))
374→			e.Return(MakeError("trap-error result is not Obj"))
375→			return
376→		}
377→	}()
378→	v := evalExp(e, car(exp), env)
379→	e.Return(v)
380→}
381→
382→func evalFunction(e *ControlFlow, fn Obj, env Obj) Obj {
383→	if ok, sym := isSymbol(fn); ok {
384→		if sym.function != nil {
385→			return sym.function
386→		}
387→
388→		if proc, ok := envGet(env, fn); ok {
389→			return proc
390→		}
391→	}
392→
393→	switch *fn {
394→	case /* scmHeadPrimitive, */ scmHeadProcedure, scmHeadNative:
395→		return fn
396→	case scmHeadPair:
397→		return evalExp(e, fn, env)
398→	}
399→	panic(fmt.Sprintf("can't apply non function: %#v", (*scmHead)(fn)))
400→}
401→
402→func (e *ControlFlow) Global(key Obj) Obj {
403→	sym := mustSymbol(key)
404→	if sym.function != nil {
405→		return sym.function
406→	}
407→	errMsg := fmt.Sprintf("variable %s not bound", sym.str)
408→	panic(MakeError(errMsg))
409→}
