 39→func equal(x, y Obj) Obj {
 40→	if x == y {
 41→		return True
 42→	}
 43→	if *x != *y {
 44→		return False
 45→	}
 46→
 47→	switch *x {
 48→	case scmHeadNumber:
 49→		if !isFixnum(x) && !isFixnum(y) {
 50→			if mustNumber(x) == mustNumber(y) {
 51→				return True
 52→			}
 53→		}
 54→		// x == y is checked already
 55→		return False
 56→	case scmHeadString:
 57→		if mustString(x) != mustString(y) {
 58→			return False
 59→		}
 60→	case scmHeadBoolean:
 61→		if x != y {
 62→			return False
 63→		}
 64→	case scmHeadSymbol:
 65→		if x != y {
 66→			return False
 67→		}
 68→	case scmHeadNull:
 69→		if *y != scmHeadNull {
 70→			return False
 71→		}
 72→	case scmHeadPair:
 73→		// TODO: maybe cycle exists!
 74→		if x != y {
 75→			if equal(car(x), car(y)) == False {
 76→				return False
 77→			}
 78→			if equal(cdr(x), cdr(y)) == False {
 79→				return False
 80→			}
 81→		}
 82→	case scmHeadStream, scmHeadProcedure /* , scmHeadPrimitive */ :
 83→		if x != y {
 84→			return False
 85→		}
 86→	case scmHeadVector:
 87→		v1 := mustVector(x)
 88→		v2 := mustVector(y)
 89→		if len(v1) != len(v2) {
 90→			return False
 91→		}
 92→		for i := 0; i < len(v1); i++ {
 93→			if v1[i] != nil || v2[i] != nil {
 94→				if equal(v1[i], v2[i]) != True {
 95→					return False
 96→				}
 97→			}
 98→		}
 99→	}
100→
101→	return True
102→}
