138→// isInteger determinate whether a float64 is actually a precise integer.
139→// Judge is according to IEEE754 standard.
140→func isPreciseInteger(f float64) bool {
141→	exp := math.Ilogb(f)
142→	if exp < 0 && exp != math.MinInt32 {
143→		return false
144→	}
145→
146→	if exp >= 52 {
147→		return true
148→	}
149→
150→	bits := math.Float64bits(f)
151→	return (bits << uint(12+exp)) == 0
152→}
