 10→type SexpReader struct {
 11→	reader *bufio.Reader
 12→	buf    []rune
 13→	// 'extended' reader is used by cora, which handles reader macro ' and [,
 14→	// and expect ; as comment
 15→	extended bool
 16→}
 17→
 18→func NewSexpReader(r io.Reader, extended bool) *SexpReader {
 19→	return &SexpReader{
 20→		reader:   bufio.NewReader(r),
 21→		extended: extended,
 22→	}
 23→}
 24→
 25→func (r *SexpReader) Read() (Obj, error) {
 26→	b, err := peekFirstRune(r.reader)
 27→	if err != nil {
 28→		return Nil, err
 29→	}
 30→
 31→	if r.extended {
 32→		switch b {
 33→		case rune(';'):
 34→			b, _, err = r.reader.ReadRune()
 35→			if err != nil {
 36→				return Nil, err
 37→			}
 38→			for b != '\n' {
 39→				b, _, err = r.reader.ReadRune()
 40→				if err != nil {
 41→					return Nil, err
 42→				}
 43→			}
 44→			return r.Read()
 45→		case rune('\''):
 46→			return r.readQuoteMacro()
 47→		case rune('['):
 48→			return r.readListMacro()
 49→		}
 50→	}
 51→
 52→	switch b {
 53→	case rune('('):
 54→		return r.readSexp()
 55→	case rune('"'):
 56→		return r.readString()
 57→	}
 58→
 59→	r.resetBuf()
 60→	r.appendBuf(b)
 61→	b, _, err = r.reader.ReadRune()
 62→	for err == nil {
 63→		if r.notSymbolChar(b) {
 64→			r.reader.UnreadRune()
 65→			break
 66→		}
 67→		r.appendBuf(b)
 68→		b, _, err = r.reader.ReadRune()
 69→	}
 70→
 71→	return tokenToObj(string(r.buf)), err
 72→}
 73→
 74→func (r *SexpReader) readQuoteMacro() (Obj, error) {
 75→	obj, err := r.Read()
 76→	if err != nil {
 77→		return obj, err
 78→	}
 79→	return cons(symQuote, cons(obj, Nil)), nil
 80→}
 81→
 82→func (r *SexpReader) readListMacro() (Obj, error) {
 83→	hd := MakeSymbol("list")
 84→	tmp := Nil
 85→	b, err := peekFirstRune(r.reader)
 86→	for err == nil && b != ']' {
 87→		if b == '.' {
 88→			hd = MakeSymbol("list-rest")
 89→		} else {
 90→			r.reader.UnreadRune()
 91→		}
 92→		var obj Obj
 93→		obj, err = r.Read()
 94→		if err == nil {
 95→			tmp = cons(obj, tmp)
 96→			b, err = peekFirstRune(r.reader)
 97→		}
 98→	}
 99→	return cons(hd, reverse(tmp)), nil
100→}
