106→func rconsForm(o Obj) Obj {
107→	if *o == scmHeadPair {
108→		return cons(MakeSymbol("cons"),
109→			cons(rconsForm(car(o)),
110→				cons(rconsForm(cdr(o)), Nil)))
111→	}
112→	return o
113→}
