115→func (r *SexpReader) readString() (Obj, error) {
116→	r.resetBuf()
117→	b, _, err := r.reader.ReadRune()
118→	for err == nil && b != rune('"') {
119→		r.appendBuf(b)
120→		b, _, err = r.reader.ReadRune()
121→	}
122→	return MakeString(string(r.buf)), err
123→}
124→
125→func (r *SexpReader) readSexp() (Obj, error) {
126→	ret := Nil
127→	b, err := peekFirstRune(r.reader)
128→	for err == nil && b != ')' {
129→		var obj Obj
130→		r.reader.UnreadRune()
131→		obj, err = r.Read()
132→		if err == nil {
133→			ret = cons(obj, ret)
134→			b, err = peekFirstRune(r.reader)
135→		}
136→	}
137→	return reverse(ret), err
138→}
139→
140→func (r *SexpReader) resetBuf() {
141→	r.buf = r.buf[:0]
142→}
143→
144→func (r *SexpReader) appendBuf(b rune) {
145→	r.buf = append(r.buf, b)
146→}
147→
148→func peekFirstRune(r *bufio.Reader) (rune, error) {
149→	b, _, err := r.ReadRune()
150→	for err == nil && unicode.IsSpace(b) {
151→		b, _, err = r.ReadRune()
152→	}
153→	return b, err
154→}
155→
156→func (r *SexpReader) notSymbolChar(c rune) bool {
157→	if unicode.IsSpace(c) {
158→		return true
159→	}
160→	switch c {
161→	case '(', '"', ')':
162→		return true
163→	case '[', ']':
164→		return r.extended
165→	}
166→	return false
167→}
