169→func tokenToObj(str string) Obj {
170→	switch str {
171→	case "true":
172→		return True
173→	case "false":
174→		return False
175→	}
176→	if v, err := strconv.ParseFloat(str, 64); err == nil {
177→		return MakeNumber(v)
178→	}
179→	return MakeSymbol(str)
180→}
